/** SIC code -> short line-of-business label used in filters & badges. */
export const SIC_LABELS: Record<string, string> = {
  "6311": "Life Insurance",
  "6321": "Accident & Health",
  "6324": "Health Plans",
  "6331": "Property & Casualty",
  "6351": "Surety & Mortgage",
  "6361": "Title Insurance",
  "6411": "Insurance Brokers",
  "6282": "Investment Advice",
};

const BY_CIK = new Map(INSURERS.map((c) => [c.cik, c]));
export function getInsurer(cik: string): InsuranceCompany | undefined {
  return BY_CIK.get(cik.padStart(10, "0"));
}

export function sicLabel(sic: string): string {
  return SIC_LABELS[sic] ?? "Insurance";
}
